// Package interop tests cross-implementation interoperability by decoding
// binary fixtures produced by the Rust reference implementation.
//
// The fixtures are generated by:
//   cargo run --bin generate_interop_fixtures -- <output_dir>
//
// This test suite verifies that the Go implementation can:
//   1. Decode every Rust-produced binary fixture
//   2. Extract the correct logical values from each fixture
//   3. Compute identical transcript hashes and session IDs
//
// This is the decode-side interop proof. The encode-side is already
// proven by the test vector verification (TEST_VECTORS.md).
package interop

import (
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"os"
	"path/filepath"
	"testing"

	"aafp-go/cbor"
	"aafp-go/frame"
	"aafp-go/handshake"
	"aafp-go/identity"
)

// fixturesDir is relative to the aafp-go root (parent of the interop package).
const fixturesDir = "../interop_fixtures"

func readFixture(t *testing.T, paths ...string) []byte {
	t.Helper()
	path := filepath.Join(append([]string{fixturesDir}, paths...)...)
	data, err := os.ReadFile(path)
	if err != nil {
		t.Fatalf("Failed to read %s: %v", path, err)
	}
	return data
}

func mustDecodeCBOR(t *testing.T, data []byte) *cbor.Value {
	t.Helper()
	v, n, err := cbor.Decode(data)
	if err != nil {
		t.Fatalf("CBOR decode failed (%d bytes): %v", data[:min(20, len(data))], err)
	}
	if n != len(data) {
		t.Fatalf("CBOR decode consumed %d, expected %d", n, len(data))
	}
	return v
}

func mustDecodeFrame(t *testing.T, data []byte) *frame.Frame {
	t.Helper()
	f, n, err := frame.Decode(data)
	if err != nil {
		t.Fatalf("Frame decode failed: %v", err)
	}
	if n != len(data) {
		t.Fatalf("Frame decode consumed %d, expected %d", n, len(data))
	}
	return f
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

