// === Handshake decode interop ===

func TestInteropClientHelloWithoutSig(t *testing.T) {
	data := readFixture(t, "handshake", "client_hello_without_sig.bin")
	v := mustDecodeCBOR(t, data)
	ch, err := handshake.ClientHelloFromCBOR(v)
	if err != nil {
		t.Fatalf("ClientHello decode failed: %v", err)
	}
	if ch.ProtocolVersion != 1 {
		t.Errorf("protocol_version: %d", ch.ProtocolVersion)
	}
	if len(ch.AgentId) != 32 {
		t.Errorf("agent_id len: %d", len(ch.AgentId))
	}
	if len(ch.PublicKey) != 1952 {
		t.Errorf("public_key len: %d", len(ch.PublicKey))
	}
	if len(ch.Nonce) != 32 {
		t.Errorf("nonce len: %d", len(ch.Nonce))
	}
	if ch.KeyAlgorithm != 1 {
		t.Errorf("key_algorithm: %d", ch.KeyAlgorithm)
	}
	// Verify agent_id matches SHA-256(public_key)
	expected := identity.AgentIdFromPubkey(ch.PublicKey)
	if hex.EncodeToString(ch.AgentId) != hex.EncodeToString(expected) {
		t.Error("agent_id does not match SHA-256(public_key)")
	}
}

func TestInteropServerHelloWithoutSig(t *testing.T) {
	data := readFixture(t, "handshake", "server_hello_without_sig.bin")
	v := mustDecodeCBOR(t, data)
	// ServerHello has 9 fields (keys 1-7, 9, 10)
	if v.Kind() != cbor.KindIntMap {
		t.Fatalf("expected int map, got %d", v.Kind())
	}
	if val := v.IntMapGet(1); val == nil || val.Uint() != 1 {
		t.Error("protocol_version should be 1")
	}
	if val := v.IntMapGet(7); val == nil || len(val.Bytes()) != 32 {
		t.Error("session_id should be 32 bytes")
	}
}

