// === AgentRecord decode interop ===

func TestInteropAgentRecordWithoutSig(t *testing.T) {
	data := readFixture(t, "handshake", "client_hello_without_sig.bin")
	_ = data // Use agent_record fixture instead
	data = readFixture(t, "agent_record", "without_sig.bin")
	v := mustDecodeCBOR(t, data)
	r, err := identity.AgentRecordFromCBOR(v)
	if err != nil {
		t.Fatalf("AgentRecord decode failed: %v", err)
	}
	if r.RecordType != "aafp-record-v1" {
		t.Errorf("record_type: %q", r.RecordType)
	}
	if len(r.AgentId) != 32 {
		t.Errorf("agent_id len: %d", len(r.AgentId))
	}
	if len(r.PublicKey) != 1952 {
		t.Errorf("public_key len: %d", len(r.PublicKey))
	}
	if len(r.Capabilities) != 1 {
		t.Fatalf("expected 1 capability, got %d", len(r.Capabilities))
	}
	if r.Capabilities[0].Name != "inference" {
		t.Errorf("capability name: %q", r.Capabilities[0].Name)
	}
	if len(r.Endpoints) != 1 || r.Endpoints[0] != "/ip4/127.0.0.1/tcp/4001" {
		t.Errorf("endpoints: %v", r.Endpoints)
	}
	if r.CreatedAt != 1735689600 {
		t.Errorf("created_at: %d", r.CreatedAt)
	}
	if r.ExpiresAt != 1736294400 {
		t.Errorf("expires_at: %d", r.ExpiresAt)
	}
	if r.KeyAlgorithm != 1 {
		t.Errorf("key_algorithm: %d", r.KeyAlgorithm)
	}
}

