// === Session ID interop ===
// Both implementations must derive the same session ID from the same
// transcript hash and nonces.

func TestInteropSessionId(t *testing.T) {
	rustSessionId := readFixture(t, "transcript", "session_id.bin")
	rustHashAfterCh := readFixture(t, "transcript", "hash_after_clienthello.bin")

	// Go derives session ID from h_after_clienthello and nonces
	clientNonce := make([]byte, 32)
	for i := range clientNonce {
		clientNonce[i] = 0x03
	}
	serverNonce := make([]byte, 32)
	for i := range serverNonce {
		serverNonce[i] = 0x04
	}
	// A-4: session ID is now bound to server agent_id
	// The Rust fixture uses SHA-256(PUBLIC_KEY_B) as the server agent_id
	// PUBLIC_KEY_B = [0x43; 1952]
	publicKeyB := make([]byte, 1952)
	for i := range publicKeyB {
		publicKeyB[i] = 0x43
	}
	serverAgentId := identity.AgentIdFromPubkey(publicKeyB)
	goSessionId := handshake.ComputeSessionId(rustHashAfterCh, clientNonce, serverNonce, serverAgentId)

	if hex.EncodeToString(goSessionId) != hex.EncodeToString(rustSessionId) {
		t.Errorf("session ID derivation:\n  Go:   %s\n  Rust: %s",
			hex.EncodeToString(goSessionId), hex.EncodeToString(rustSessionId))
	}
}

// === Full round-trip interop ===
// Decode Rust fixture, re-encode with Go, verify identical bytes.

func TestInteropRoundTripClientHello(t *testing.T) {
	rustBytes := readFixture(t, "handshake", "client_hello_without_sig.bin")
	v, _, err := cbor.Decode(rustBytes)
	if err != nil {
		t.Fatal(err)
	}
	goBytes, err := cbor.Encode(v)
	if err != nil {
		t.Fatal(err)
	}
	rustHash := sha256.Sum256(rustBytes)
	goHash := sha256.Sum256(goBytes)
	if rustHash != goHash {
		t.Errorf("ClientHello round-trip hash mismatch:\n  Rust: %s\n  Go:   %s",
			hex.EncodeToString(rustHash[:]), hex.EncodeToString(goHash[:]))
	}
}

