func TestInteropRoundTripAllFrames(t *testing.T) {
	fixtures := []string{
		"data_empty", "data_stream42", "handshake",
		"rpc_request", "ping", "data_flags_more",
	}
	for _, name := range fixtures {
		t.Run(name, func(t *testing.T) {
			rustBytes := readFixture(t, "frames", name+".bin")
			f, _, err := frame.Decode(rustBytes)
			if err != nil {
				t.Fatal(err)
			}
			goBytes, err := frame.Encode(f)
			if err != nil {
				t.Fatal(err)
			}
			rustHash := sha256.Sum256(rustBytes)
			goHash := sha256.Sum256(goBytes)
			if rustHash != goHash {
				t.Errorf("%s round-trip hash mismatch:\n  Rust: %s\n  Go:   %s",
					name, hex.EncodeToString(rustHash[:]), hex.EncodeToString(goHash[:]))
			}
		})
	}
}

